-/* Inline icons with tooltip */
-.inline-icon-wrapper {
-  position: relative;
-  display: inline-flex;
-  align-items: center;
-  margin-right: var(--tnz-space-1);
+/* Semantic cross-reference links (Op, Fn, Guide, etc.) */
+.semantic-link {
+  text-decoration: none;
 }

-.inline-icon-wrapper::after {
-  content: attr(data-tooltip);
-  position: absolute;
-  left: 50%;
-  bottom: 100%;
-  transform: translateX(-50%);
-  padding: 2px 6px;
-  background: var(--tnz-neutral-800);
-  color: var(--tnz-neutral-400);
-  font-size: 10px;
-  border-radius: 3px;
-  white-space: nowrap;
-  opacity: 0;
-  pointer-events: none;
-  transition: opacity 0.15s;
-  margin-bottom: 2px;
+.semantic-link:hover {
+  text-decoration: underline;
 }

-.inline-icon-wrapper:hover::after {
-  opacity: 1;
+/* Hide icons in inline prose. They are shown only in See Also lists. */
+.semantic-link .inline-icon {
+  display: none;
 }

-:root[data-theme="light"] .inline-icon-wrapper::after {
-  background: var(--tnz-neutral-200);
-  color: var(--tnz-neutral-500);
+/* Tighten code padding inside semantic links so there's no gap before
+   surrounding punctuation (e.g., the colon in "<Op>from</Op>: …"). */
+.semantic-link code {
+  padding-inline: 0.2em;
 }

-.inline-icon {
-  display: inline;
-  vertical-align: middle;
-  color: var(--tnz-neutral-600);
+/* Semantic-link list items use the icon as their marker without affecting
+   neighboring plain-text bullets in mixed lists. */
